import { SysConstants, Cookie, CookieHelper } from "@/helpers";
import { useUserStore } from "@/stores";
import { UserService } from "./data/user";

const userStore = useUserStore();

/**
 * 使用者權限相關處理
 */
export class AuthService {
  static #ERR_NO_AUTH_USER = "請先登入！";

  /**
   * 檢驗使用者是否有權限（即是否已登入）。
   * 若檢查結果為沒有權限，則會順便清除使用者資料狀態。
   * @returns {boolean} 有權限回傳 true，否則回傳 false。
   */
  static checkUserAuth() {
    // Cookie 中若有 token 則代表已登入（有權限）
    const hasLogin = CookieHelper.hasCookie(SysConstants.cookieTokenName);

    // 若未登入則清除使用者資料狀態
    if (!hasLogin) {
      userStore.remove();
    }

    return hasLogin;
  }

  /**
   * 取得使用者 token。
   * @returns {string} Token。
   */
  static getToken() {
    return CookieHelper.getCookie(SysConstants.cookieTokenName);
  }

  /**
   * 登入。
   * @param {string} email 使用者 email。
   * @param {string} password 使用者密碼。
   * @returns {UserData} 使用者資料。
   * @throws {Error} 若登入失敗則拋出錯誤。
   */
  static async login(email, password) {
    // API login
    const response = await UserService.login(email, password);

    // 將 token 記錄至 cookie
    const cookie = new Cookie(SysConstants.cookieTokenName);
    cookie.setMaxAge(SysConstants.cookieTokenTime);
    cookie.setValue(response.accessToken);
    CookieHelper.saveCookie(cookie);

    // 設定使用者資料狀態
    userStore.set(response.user);

    return response.user;
  }

  /**
   * 登出。
   */
  static logout() {
    // 移除 cookie
    const cookie = new Cookie(SysConstants.cookieTokenName);
    CookieHelper.removeCookie(cookie);

    // 清除使用者資料狀態
    userStore.remove();
  }

  /**
   * 修改自己的使用者資料，必須先登入才能執行。
   * @param {UserData} userData 使用者資料。
   * @returns {UserData} 更新後的使用者資料。
   * @throws {Error} 若未登入或執行過程中發生失敗則拋出錯誤。
   */
  static async modifySelf(userData) {
    // 檢查是否有權限
    if (!this.checkUserAuth()) {
      throw Error(this.#ERR_NO_AUTH_USER);
    }

    // API 修改資料
    const user = await UserService.modifySelf(this.getToken(), userStore.id, userData);

    // 設定使用者資料狀態
    userStore.set(user);

    return user;
  }

  /**
   * 刪除自己的使用者資料，必須先登入才能執行。
   * @throws {Error} 若未登入或執行過程中發生失敗則拋出錯誤。
   */
  static async deleteSelf() {
    // 檢查是否有權限
    if (!this.checkUserAuth()) {
      throw Error(this.#ERR_NO_AUTH_USER);
    }

    // API 刪除資料
    await UserService.deleteSelf(this.getToken(), userStore.id);

    // 執行 logout
    this.logout();
  }
}
