import { defineStore } from "pinia";
import { ref } from "vue";

/**
 * 使用者資料狀態管理。
 */
export const useUserStore = defineStore("userStore", () => {
  let id = ref(null); // id
  let name = ref(""); // 姓名
  let email = ref(""); // Email
  let mobilePhone = ref(""); // 手機
  let rocId = ref(""); // 身份證字號
  let gender = ref(""); // 性別

  /**
   * 設定完整的使用者資料（密碼除外）。
   * @param {UserData} data 使用者資料。
   */
  function set(data) {
    id.value = data.id;
    name.value = data.name;
    email.value = data.email;
    mobilePhone.value = data.mobilePhone;
    rocId.value = data.rocId;
    gender.value = data.gender;
  }

  /**
   * 清除使用者資料。
   */
  function remove() {
    id.value = null;
    name.value = "";
    email.value = "";
    mobilePhone.value = "";
    rocId.value = "";
    gender.value = "";
  }

  /**
   * 將使用者資料串接成字串回傳。
   * @returns {string} 使用者資料字串。
   */
  function toString() {
    return `${id.value}, ${name.value}, ${email.value}, ${mobilePhone.value}, ${rocId.value}, ${gender.value}`;
  }

  return { id, name, email, mobilePhone, rocId, gender, set, remove, toString };
});
